import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"马里奥的管钳","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/马里奥的管钳.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/马里奥的管钳.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/马里奥的管钳.md"};function _(l,a,p,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"马里奥的管钳",tabindex:"-1"},[s("马里奥的管钳 "),e("a",{class:"header-anchor",href:"#马里奥的管钳","aria-label":'Permalink to "马里奥的管钳"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序006")])])],-1),o('<h1 id="马里奥的管钳-1" tabindex="-1">马里奥的管钳 <a class="header-anchor" href="#马里奥的管钳-1" aria-label="Permalink to &quot;马里奥的管钳&quot;">​</a></h1><p>马里奥的管钳<br> D+500<br> 魔幻本质<br> 外形普通的管钳，上面附着一层火焰，也许是管钳正在愤怒。（这层火焰并非实际的火焰，但会让你摸起来暖暖的）</p><p>这视为一把短棍，伤害5L，格挡1，你可以使用一个标准动作，攻击一个生物的头部，这次检定不会造成伤害，而会将伤害的出数转化为晕眩点数。以标准形式豁免，同时附带一点不可豁免的麻痹点数。</p><p>备注：这把管钳的主人很有名，他自称是个水管工，但他从不修管道，他只是在管道里钻进钻出，跳来跳去。整日忙着与恶势力战斗、拯救王国、寻找公主什么的。他有时会化装成青蛙、浣熊、甚至地藏菩萨。有时他还会放火球，扔锤子……但他从不！请注意，是“从不”用这件水管工必备的工具。于是，这把管钳愤怒了，它火冒三丈，它要证明管钳完全是可以参加战斗的！</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
